function outer() {
  const message = "Hello";  // 外层变量
  function inner() {
    console.log(message);    // 引用外层变量 → 闭包！
  }
  return inner;
}

const fn = outer();  // outer 执行完，message 本该销毁
fn();  // "Hello" — message 被闭包保持，仍然存活！

function createCounter() {
  let count = 0;  // ① 创建词法环境: { count: 0 }
  // ② 返回的函数绑定到当前词法环境
  return () => {
    count++;       // ③ 通过闭包引用访问 count
    return count;
  };
}
// ④ createCounter 执行完，但 { count } 被闭包引用
//    垃圾回收器不会回收它
const counter = createCounter();
counter();  // 1
counter();  // 2 — count 持续存活

function createWallet(initial = 0) {
  let balance = initial;  // 私有变量
  return {
    deposit(amount) {
      if (amount <= 0) throw new Error("金额必须>0");
      balance += amount;
      return balance;
    },
    withdraw(amount) {
      if (amount > balance) throw new Error("余额不足");
      balance -= amount;
      return balance;
    },
    getBalance() { return balance; }
  };
}
const w = createWallet(100);
w.deposit(50);    // 150
w.withdraw(30);   // 120
// w.balance = 0;  // ❌ 无效！balance 不是属性

function createMultiplier(factor) {
  return (n) => n * factor;  // 闭包记住 factor
}
const double = createMultiplier(2);
const triple = createMultiplier(3);
double(5);   // 10
triple(5);   // 15

function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn(...args);
    }
    return (...more) => curried(...args, ...more);
  };
}
const add = (a, b, c) => a + b + c;
const add5 = curry(add)(5);  // 闭包记住 a=5
add5(3, 2);  // 10

function debounce(fn, ms) {
  let timer;  // 闭包保持 timer 引用
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), ms);
  };
}
const search = debounce(fetchResults, 300);

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 3, 3, 3 — 共享同一个i！

for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 0, 1, 2 — 每次循环创建新i

function Counter() {
  const [count, setCount] = useState(0);
  // 这个回调"记住"的是点击时的 count
  const handleClick = () => {
    setTimeout(() => {
      console.log(count); // 可能是旧值！
    }, 1000);
  };
  // ✅ 解决：函数式更新
  const handleFix = () => {
    setCount(c => c + 1); // c 永远是最新的
  };
}

// ✅ 闭包常用模式
const counter = (() => {  // IIFE
  let count = 0;
  return { inc: () => ++count, get: () => count };
})();

